challenges.solution:
uniform float u_time;
out vec4 fragColor;

void main() {
    const float TAU = 6.28318;
    const float offset = TAU / 3.0;

    float r = sin(u_time)              * 0.5 + 0.5;
    float g = sin(u_time + offset)     * 0.5 + 0.5;
    float b = sin(u_time + offset * 2.0) * 0.5 + 0.5;

    fragColor = vec4(r, g, b, 1.0);
}

